SELECT programs.program_id, programs.title, program_areas.area_name
FROM programs
INNER JOIN program_areas ON programs.program_area_id = program_areas.program_area_id;

SELECT title, description
FROM programs
WHERE program_area_id = 1;

SELECT program_id, title, status
FROM programs
WHERE program_id IN (SELECT program_id FROM access_logs);

SELECT SUM(population) AS total_population
FROM (
    SELECT population FROM states
    UNION ALL
    SELECT population FROM cities
);
